import hashlib
import time


collectionNames = {
    "Invoice": "sm_sapinvoice_d68c98"
}


def create_hash(v):
    if not v:
        return ""
    return "0x" + hashlib.sha3_256(str(v).encode('utf-8')).hexdigest()


def fetch_invoice_docs(db, invoice_numbers):
    invoice_collection = collectionNames.get("Invoice")
    if not invoice_collection:
        raise Exception("Invoice collection not configured")

    docs = []
    # If invoice_numbers is a single string, convert to list
    if isinstance(invoice_numbers, str):
        invoice_numbers = [invoice_numbers]

    for inv_num in invoice_numbers:
        inv_num_str = str(inv_num).strip()
        if not inv_num_str:
            continue
        try:
            # Use same find_one wrapper pattern as Sap_Invoice.py
            doc = db.find_one(
                invoice_collection,
                {"DocDetails.D_DocumentNumber": inv_num_str}
            )
            if doc:
                docs.append(doc)
                print(f"Fetched invoice doc for: {inv_num_str}")
            else:
                print(f"No invoice doc found for: {inv_num_str}")
        except Exception as e:
            print(f"Error fetching invoice {inv_num_str}: {e}")

    return docs


def run(doc: dict, db: any, config) -> dict:
    # 1. Debug prints
    print(f"doc count: {len(doc)} :: doc content: {doc}")

    # 2. Extract Invoice Numbers (relatedInvoiceNumbers or DocumentNumber)
    invoice_numbers = doc.get("relatedInvoiceNumbers", [])
    if not invoice_numbers:
        doc_num = doc.get("DocumentNumber")
        if doc_num:
            invoice_numbers = [doc_num]

    if not invoice_numbers or (isinstance(invoice_numbers, list) and not any(invoice_numbers)):
        raise Exception("No invoice numbers found for payment. Document ignored.")

    # 3. Fetch related invoice docs from common collection
    invoice_docs = fetch_invoice_docs(db, invoice_numbers)
    if not invoice_docs:
        raise Exception(f"No invoice documents found for parent references: {invoice_numbers}")

    print(f"Fetched {len(invoice_docs)} invoice doc(s)")

    # 4. Key Identifiers
    # ClearingDocno is primary Payment number. RefDocNumber as fallback.
    payment_key = (doc.get("ClearingDocno", "") or doc.get("DocumentNumber", "") or "").strip()
    if not payment_key:
        raise Exception("No payment key found (ClearingDocno/DocumentNumber)")

    # 5. Aggregate items from all matched invoices
    all_invoice_items = []
    for inv_doc in invoice_docs:
        items = inv_doc.get("OrderedItems", [])
        if isinstance(items, list):
            all_invoice_items.extend(items)

    total_quantity = sum(
        float(item.get("I_Quantity", 0) or 0)
        for item in all_invoice_items
    )

    # Use first invoice for header references
    first_invoice = invoice_docs[0]

    # 6. Initialize target structure based on schema
    target = {
        "DocDetails": {
            "D_DocumentNumber":               payment_key,
            "D_DocumentCreationDate":         int(time.time() * 1000),
            "D_ParentDocumentNumbers":        invoice_numbers,
            "D_MinimumPaymentDuePriceCurrency": "INR",
            "D_MinimumPaymentDueMinPrice":    0,
            "D_PaymentDueDate":               "",
            "D_PaymentMethod":                "",
            "D_OrderStatus":                  "",
            "D_TotalPaymentDuePriceCurrency": doc.get("CurrencyKey", "INR"),
            "D_TotalPaymentDueMinPrice":      float(doc.get("NetAmount", 0) or 0),
            "D_ScheduledPaymentDate":         "",
            "D_ExpectedDeliveryDate":         "",
            "D_ExpiryDate":                   "",
            "D_PaymentTerms":                 doc.get("TransactionType", ""),
            "D_ItemCount":                    len(all_invoice_items),
            "D_TotalQuantity":                total_quantity,
            "D_OffersAddOn":                  first_invoice.get("DocDetails", {}).get("D_OffersAddOn", []),
            "D_DeliveryAddress":              doc.get("Address", ""),
            "D_Identifier":                   create_hash(payment_key)
        },
        "Seller": first_invoice.get("Seller", {}),
        "OrderedItems": all_invoice_items
    }

    # 7. Map financial breakdown labels to D_OffersAddOn
    for label in ["NetAmount", "InvoiceAmount", "TDSAmount"]:
        val = doc.get(label)
        if val is not None:
            try:
                target["DocDetails"]["D_OffersAddOn"].append({
                    "D_Name":  label,
                    "D_Price": float(val),
                    "D_Type":  "value",
                    "D_Title": label
                })
            except (ValueError, TypeError):
                pass

    return target
